    else:
        # Field not present, so no match
        return False

    for operator, expected_value in filter_spec.items():
        if operator == "==":
            if field_value != expected_value:
                return False
        elif operator == "!=":
            if field_value == expected_value:
                return False
        elif operator == "<":
            if not (isinstance(field_value, (int, float)) and field_value < expected_value):
                return False
        elif operator == "<=":
            if not (isinstance(field_value, (int, float)) and field_value <= expected_value):
                return False
        elif operator == ">":
            if not (isinstance(field_value, (int, float)) and field_value > expected_value):
                return False
        elif operator == ">=":
            if not (isinstance(field_value, (int, float)) and field_value >= expected_value):
                return False
        elif operator == "in":
            if not (isinstance(field_value, (list, tuple)) and expected_value in field_value):
                return False
        elif operator == "not_in":
            if not (isinstance(field_value, (list, tuple)) and expected_value not in field_value):
                return False
        else:
            # Unknown operator, skip or fail?
            # For strictness, we can consider unknown operators as a mismatch
            return False
    return True
