from collections import Counter, defaultdict
import pickle

def get_index_statistics(
    index_path: str
) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

Args:
    index_path: Path to the LEANN index file

Returns:
    Dictionary containing:
    {
        "total_passages": total number of passages,
        "metadata_fields": list of unique metadata field names,
        "field_value_counts": dictionary of field value counts
    }

Raises:
    FileNotFoundError: If index metadata file is not found"""
    meta_path = Path(index_path) / f"{index_path}.meta.json"
    if not meta_path.exists():
        raise FileNotFoundError(f"Index metadata file not found at {meta_path}")

    with open(meta_path, 'r') as f:
        meta_data = json.load(f)

    total_passages = meta_data.get('total_count', 0)

    # Get the passage source file
    passage_sources = meta_data.get('passage_sources', [])
    if not passage_sources:
        return {
            "total_passages": total_passages,
            "metadata_fields": [],
            "field_value_counts": {}
        }

    # Assume first source for simplicity (LEANN supports multiple, but we take first)
    passage_source = passage_sources[0]
    passage_file_relative = passage_source.get('path')
    if not passage_file_relative:
        return {
            "total_passages": total_passages,
            "metadata_fields": [],
            "field_value_counts": {}
        }

    # Resolve the absolute path
    passage_file = meta_path.parent / passage_file_relative
    if not passage_file.exists():
        return {
            "total_passages": total_passages,
            "metadata_fields": [],
            "field_value_counts": {}
        }

    # Load the passage file
    with open(passage_file, 'rb') as f:
        passages = pickle.load(f)

    # Collect metadata fields and their values
    metadata_fields = set()
    field_values = defaultdict(Counter)

    for passage in passages:
        metadata = passage.get('metadata', {})
        for field, value in metadata.items():
            metadata_fields.add(field)
            field_values[field][value] += 1

    return {
        "total_passages": total_passages,
        "metadata_fields": list(metadata_fields),
        "field_value_counts": {k: dict(v) for k, v in field_values.items()}
    }

