    total = len(passages)
    if total == 0:
        return {
            "coverage_percentage": 0.0,
            "field_coverage": {field: 0.0 for field in required_fields},
            "missing_fields": required_fields.copy()
        }

    # Check which required fields are missing in all passages
    all_missing = True
    present_fields = set()
    for passage in passages:
        metadata = passage.get('metadata', {})
        present_fields.update(metadata.keys())
    missing_in_all = [field for field in required_fields if field not in present_fields]
    if not missing_in_all:
        all_missing = False

    # Calculate coverage
    covered = 0
    field_coverages = defaultdict(int)
    for passage in passages:
        metadata = passage.get('metadata', {})
        missing = 0
        for field in required_fields:
            if field not in metadata:
                missing += 1
        if missing == 0:
            covered += 1
        for field in required_fields:
            if field in metadata:
                field_coverages[field] += 1

    coverage_percentage = (covered / total) * 100
    field_coverage = {field: (field_coverages[field] / total) * 100 for field in required_fields}

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_in_all if all_missing else []
    }
