from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
import json

def get_passages_by_multiple_criteria(
    index_path: str,
    criteria: Dict[str, Any]
) -> List[Dict[str, Any]]:
    """Retrieve passages from an index that match multiple metadata criteria (AND logic).

    Args:
        index_path: Path to the LEANN index file
        criteria: Dictionary of metadata field-value pairs that must all match

    Returns:
        List of passage dictionaries that match all criteria

    Raises:
        FileNotFoundError: If index metadata file is not found"""
    try:
        passage_manager = PassageManager(index_path)
    except FileNotFoundError:
        raise FileNotFoundError("Index metadata file not found")
    except Exception as e:
        # Reraise only if it's a FileNotFoundError, otherwise let it propagate
        if isinstance(e, FileNotFoundError):
            raise
        else:
            raise  # re-raise other exceptions

    # Get the metadata file path
    if not passage_manager.passage_sources:
        raise FileNotFoundError("No passage sources found in index")

    meta_source = passage_manager.passage_sources[0]
    meta_file_path = Path(index_path).parent / meta_source['path']

    # Check if the metadata file exists
    if not meta_file_path.exists():
        raise FileNotFoundError(f"Metadata file not found at {meta_file_path}")

    # Read all passage IDs from the metadata file
    passage_ids = []
    with open(meta_file_path, 'r', encoding='utf-8') as f:
        for line_num, line in enumerate(f, 1):
            try:
                data = json.loads(line.strip())
                passage_id = data.get('id')
                if passage_id:
                    passage_ids.append(passage_id)
            except:
                continue

    # Filter passages by criteria
    matching_passages = []
    for passage_id in passage_ids:
        try:
            passage_dict = passage_manager.get_passage(passage_id)
            # Check if all criteria are met
            meets_criteria = True
            for key, expected_value in criteria.items():
                if passage_dict.get(key) != expected_value:
                    meets_criteria = False
                    break
            if meets_criteria:
                matching_passages.append(passage_dict)
        except KeyError:
            # Skip if passage not found
            continue

    return matching_passages
